function NPCActionFactory:TryPostInitAction(Option, Action, Info, OwnerNpc)
  local ActionType = Action.action_type
  local ActionKlass = NPCActionFactory.Registry[ActionType]
  local PostInit = ActionKlass and ActionKlass.PostInit or false
  PostInit = PostInit ~= NPCActionBase.PostInit and PostInit or false
  if PostInit then
    return PostInit(Option, Action, Info, OwnerNpc) or false
  end
  return false
end

function NPCActionFactory:Get(Option, Action, Info, DontCreate, OwnerNpc)
  local ActionKlass = NPCActionFactory.Registry[Action.action_type]
  if ActionKlass then
    return ActionKlass(Option, Action, Info, OwnerNpc)
  elseif DontCreate then
    return nil
  else
    return NPCActionBase(Option, Action, Info, OwnerNpc)
  end
end

return NPCActionFactory
